SourceCode.Declaration:
/// <summary>
/// Asset import
/// </summary>
public class ETG_Acu_AssetImport extends ETG_Acu_DataImportBase
{
}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_AssetImport  assetImport;

    assetImport = ETG_Acu_AssetImport::construct();

    if (assetImport.prompt())
    {
        assetImport.runOperation();
    }
}

public static ETG_Acu_AssetImport construct()
{
    return new ETG_Acu_AssetImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    AssetFixedAssetV2Entity  asset;

    AssetId    assetId;

    assetId = conpeek(_con, 1);

    select firstonly forupdate asset
        where asset.FixedAssetNumber == assetId;

    if (!asset)
    {
        asset.FixedAssetNumber      = conpeek(_con, 1);
        asset.Reference             = conpeek(_con, 2);
        asset.DocumentLocation      = conpeek(_con, 3);
        asset.FixedAssetGroupId     = conpeek(_con, 4);
        asset.Name                  = conpeek(_con, 5);
        asset.PropertyType          = conpeek(_con, 6);
        asset.Quantity              = conpeek(_con, 7);
        asset.Type                  = conpeek(_con, 8);
        asset.UnitCost              = conpeek(_con, 9);
        asset.UnitOfMeasure         = conpeek(_con, 10);
        asset.AssetLocationId       = conpeek(_con, 11);
        asset.insert();
    }
    else
    {
        asset.Reference             = conpeek(_con, 2);
        asset.DocumentLocation      = conpeek(_con, 3);
        asset.FixedAssetGroupId     = conpeek(_con, 4);
        asset.Name                  = conpeek(_con, 5);
        asset.PropertyType          = conpeek(_con, 6);
        asset.Quantity              = conpeek(_con, 7);
        asset.Type                  = conpeek(_con, 8);
        asset.UnitCost              = conpeek(_con, 9);
        asset.UnitOfMeasure         = conpeek(_con, 10);
        asset.AssetLocationId       = conpeek(_con, 11);
        asset.update();
    }
}

/// <summary>
///Import asset
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = "@ETG_ENG_Labels:ImpAsset";

    return ret;
}
